questions.answer:
WITH cte AS (
  SELECT *, ROW_NUMBER() OVER (
    PARTITION BY email ORDER BY employee_id
  ) AS rn
  FROM employees
)
DELETE FROM employees
WHERE employee_id IN (
  SELECT employee_id FROM cte WHERE rn > 1
);

